// Import necessary modules
const { Client, GatewayIntentBits, Routes } = require('discord.js');
const { REST } = require('@discordjs/rest');
const { TOKEN, CLIENT_ID, GUILD_ID } = require('./config.json');

// Create a new client instance
const client = new Client({ intents: [GatewayIntentBits.Guilds] });

// Define the slash command
const commands = [
  {
    name: 'ban',
    description: 'Ban a user from the server',
    options: [
      {
        name: 'user',
        description: 'The user to ban',
        type: 6, // USER type
        required: true,
      },
      {
        name: 'reason',
        description: 'The reason for the ban',
        type: 3, // STRING type
        required: false,
      },
    ],
  },
];

// Register the slash command with Discord
const rest = new REST({ version: '10' }).setToken(TOKEN);

(async () => {
  try {
    console.log('Started refreshing application (/) commands.');

    await rest.put(Routes.applicationGuildCommands(CLIENT_ID, GUILD_ID), {
      body: commands,
    });

    console.log('Successfully reloaded application (/) commands.');
  } catch (error) {
    console.error(error);
  }
})();

// Handle the slash command interaction
client.on('interactionCreate', async (interaction) => {
  if (!interaction.isChatInputCommand()) return;

  if (interaction.commandName === 'ban') {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    const member = await interaction.guild.members.fetch(user.id);

    if (!member) {
      return interaction.reply({ content: 'That user is not in this server!', ephemeral: true });
    }

    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return interaction.reply({ content: 'You do not have permission to ban members!', ephemeral: true });
    }

    try {
      await member.ban({ reason });
      await interaction.reply({ content: `${user.tag} has been banned from the server. Reason: ${reason}`, ephemeral: true });
    } catch (error) {
      console.error(error);
      await interaction.reply({ content: 'An error occurred while trying to ban the user.', ephemeral: true });
    }
  }
});

// Log in to Discord with your client's token
client.login(TOKEN);
```

