```cpp
#include <string>
#include <regex>

std::string markdownToHTML(const std::string& markdown) {
    std::string html;
    std::regex headingRegex(R"(^(#{1,6})\s*(.+?)\s*#*$)");
    std::regex emphasisRegex(R"((\*\*|__)(.*?)\1)");
    std::regex linkRegex(R"(\[(.*?)\]\((.*?)\))");
    std::regex codeBlockRegex(R"(^```(.*?)\n([\s\S]*?)\n```$)");
    std::regex inlineCodeRegex(R"(`(.*?)`$)");

    std::sregex_iterator iter(markdown.begin(), markdown.end(), headingRegex);
    std::sregex_iterator end;

    for (std::sregex_iterator i = iter; i != end; ++i) {
        std::smatch match = *i;
        int level = match[1].str().length();
        std::string text = match[2].str();
        html += "<h" + std::to_string(level) + ">" + text + "</h" + std::to_string(level) + ">";
    }

    html = std::regex_replace(html, emphasisRegex, "<em>$2</em>");
    html = std::regex_replace(html, linkRegex, "<a href=\"$2\">$1</a>");

    iter = std::sregex_iterator(markdown.begin(), markdown.end(), codeBlockRegex);
    for (std::sregex_iterator i = iter; i != end; ++i) {
        std::smatch match = *i;
        std::string lang = match[1].str();
        std::string code = match[2].str();
        html += "<pre><code" + (lang.empty() ? "" : " class=\"language-" + lang + "\"") + ">" + code + "</code></pre>";
    }

    html = std::regex_replace(html, inlineCodeRegex, "<code>$1</code>");

    return html;
}
```

This function uses regular expressions to match various Markdown syntax elements and replace them with their corresponding HTML tags. Here's a breakdown of the different regex patterns used:

- `headingRegex`: Matches Markdown headers (`#`, `##`, `###`, etc.) and captures the header level and text.
- `emphasisRegex`: Matches text wrapped in `**` or `__` for bold or italic emphasis.
- `linkRegex`: Matches Markdown links in the format `[link text](link URL)`.
- `codeBlockRegex`: Matches multi-line code blocks enclosed in triple backticks (`````) with an optional language specifier.
- `inlineCodeRegex`: Matches inline code wrapped in single backticks (``).

The function iterates through the input Markdown text, matches the different syntax elements using the regular expressions, and replaces them with the corresponding HTML tags.

Note that this implementation is a simplified example and does not cover all possible Markdown syntax elements. For a more comprehensive solution, you may want to consider using a dedicated Markdown parsing library or a more robust regex pattern.

